import React from 'react';
import SmallChops from  './Menu';

function App() {
  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', textAlign: 'center' }}>
      <header style={{ padding: '50px', borderBottom: '2px solid #D4AF37' }}>
        <h1 style={{ color: '#D4AF37', fontSize: '3.5rem', margin: 0 }}>ÀMÍ BY T</h1>
        <p style={{ color: '#E07A5F', letterSpacing: '5px', textTransform: 'uppercase' }}>Taste and Style</p>
      </header>

      <main style={{ padding: '20px' }}>
        <SmallChops />
      </main>
      
      <footer style={{ padding: '20px', color: '#333' }}>
        <p>© 2026 Àmí by T | Lagos</p>
      </footer>
    </div>
  );
}

export default App;
